<?php
require_once dirname(__DIR__).'/helpers.php';require_admin();$pageTitle='Berita Kampanye';
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();if(($_POST['action']??'')==='delete'){$stmt=db()->prepare('DELETE FROM campaign_updates WHERE id=?');$stmt->execute([(int)$_POST['id']]);flash('success','Berita dihapus.');}else{$stmt=db()->prepare('INSERT INTO campaign_updates(campaign_id,title,content) VALUES(?,?,?)');$stmt->execute([(int)$_POST['campaign_id'],trim($_POST['title']),trim($_POST['content'])]);flash('success','Berita kampanye ditambahkan.');}redirect('admin/updates.php');}
$campaigns=db()->query("SELECT id,title FROM campaigns ORDER BY title")->fetchAll();$rows=db()->query("SELECT u.*,c.title campaign_title FROM campaign_updates u JOIN campaigns c ON c.id=u.campaign_id ORDER BY u.created_at DESC")->fetchAll();include dirname(__DIR__).'/partials/header.php';include __DIR__.'/nav.php';?>
<section class="admin-content container"><div class="admin-heading"><div><span class="eyebrow">Konten</span><h1>Berita Perkembangan</h1></div></div><div class="admin-split"><div class="glass form-card"><form method="post" class="stack-form"><?=csrf_field()?><label>Kampanye<select name="campaign_id" required><?php foreach($campaigns as $c):?><option value="<?=$c['id']?>"><?=e($c['title'])?></option><?php endforeach;?></select></label><label>Judul berita<input name="title" required></label><label>Isi berita<textarea name="content" rows="7" required></textarea></label><button class="btn primary">Publikasikan Berita</button></form></div><div class="glass panel"><h2>Berita terbit</h2><div class="timeline admin-timeline"><?php foreach($rows as $r):?><article><time><?=date('d M Y',strtotime($r['created_at']))?></time><h3><?=e($r['title'])?></h3><small><?=e($r['campaign_title'])?></small><p><?=e($r['content'])?></p><form method="post" onsubmit="return confirm('Hapus berita?')"><?=csrf_field()?><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?=$r['id']?>"><button class="text-danger">Hapus</button></form></article><?php endforeach;?></div></div></div></section>
<?php include dirname(__DIR__).'/partials/footer.php'; ?>
